<h1 class="h3 mb-1">QuickBooks mappings</h1><p class="text-muted mb-4">Map portal services, taxes, discounts, and payment methods to QuickBooks objects.</p><div class="row g-4"><div class="col-lg-5"><div class="card"><div class="card-body"><form method="post"><?=csrf_field()?><select class="form-select mb-2" name="mapping_type"><option>income_account</option><option>asset_account</option><option>payment_method</option><option>tax_code</option><option>service_item</option><option>discount_item</option></select><input class="form-control mb-2" name="local_reference_type" placeholder="Local type, e.g. service"><input class="form-control mb-2" type="number" name="local_reference_id" placeholder="Local ID"><input class="form-control mb-2" name="local_key" placeholder="Local key"><input class="form-control mb-2" name="quickbooks_id" placeholder="QuickBooks ID" required><input class="form-control mb-2" name="quickbooks_name" placeholder="QuickBooks name"><div class="form-check"><input class="form-check-input" type="checkbox" name="active" checked><label class="form-check-label">Active</label></div><button class="btn btn-primary mt-3">Save mapping</button></form></div></div></div><div class="col-lg-7"><div class="card"><div class="card-body"><table class="table"><thead><tr><th>Type</th><th>Local</th><th>QuickBooks</th></tr></thead><tbody><?php foreach($mappings as $m):?><tr><td><?=e($m['mapping_type'])?></td><td><?=e(($m['local_reference_type']?:$m['local_key']).' '.($m['local_reference_id']?:''))?></td><td><?=e($m['quickbooks_name'].' ('.$m['quickbooks_id'].')')?></td></tr><?php endforeach?></tbody></table></div></div></div></div>
